mapper.select:
/*mapper.post.PostMapper.find */ SELECT p.POST_ID AS postId , p.USER_EMAIL AS userEmail , p.CATEGORY_CODE AS categoryCode , p.TITLE AS title , p.CREATED_AT AS createdAt , p.UPDATED_AT AS updatedAt , p.DELETED_AT AS deletedAt , u.NICKNAME AS nickname , (SELECT COUNT(*) FROM likes WHERE TARGET_ID = p.POST_ID) AS likes , (SELECT COUNT(*) FROM comments WHERE POST_ID = p.POST_ID AND DEL_YN = 'N') AS comments , (SELECT image_url FROM post_images WHERE post_id = p.POST_ID AND del_yn = 'N' ORDER BY sort_order ASC LIMIT 1) AS thumbnail , p.DEL_YN AS delYn , (SELECT report_status_code FROM reports WHERE TARGET_CODE = '01' AND TARGET_ID = p.POST_ID) AS reportStatusCode , (SELECT target_id FROM reports WHERE TARGET_CODE = '01' AND TARGET_ID = p.POST_ID) AS targetId FROM posts p LEFT OUTER JOIN users u ON p.USER_EMAIL = u.EMAIL WHERE 1=1
AND (title like CONCAT('%', #{word}, '%') OR u.nickname like CONCAT('%', #{word}, '%'))
AND p.DEL_YN = 'N'
AND p.DEL_YN = #{delYn}
AND p.CATEGORY_CODE = #{categoryCode}
AND p.POST_ID < #{lastId}
ORDER BY p.POST_ID DESC LIMIT #{size}
OFFSET #{offset}

    	/*mapper.post.PostMapper.findPostCount */
        SELECT 
            count(*) AS count
        FROM posts p LEFT OUTER JOIN users u ON p.USER_EMAIL = u.EMAIL
        WHERE
        	1=1

	    	AND (title like CONCAT('%', #{word}, '%') OR u.nickname like CONCAT('%', #{word}, '%'))


	        AND CATEGORY_CODE = #{categoryCode}


	        AND DEL_YN = #{delYn}


        	AND created_at between STR_TO_DATE(CONCAT(#{today},' 00:00:00'), '%Y-%m-%d %H:%i:%s') and STR_TO_DATE(CONCAT(#{today},' 23:59:59'), '%Y-%m-%d %H:%i:%s')

mapper.update:
